#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;skip=false;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--skip-build)skip=true;shift;;*)archphene_die "unknown argument: $1";;esac;done;[[ "$skip" == true ]] || "$ARCHPHENE_SCRIPTS_DIR/build-manager-podman.sh";manager_apk="$ARCHPHENE_ROOT/prototypes/linux-app-manager-stub/out-linux/archphene.apk";terminal_apk="$ARCHPHENE_ROOT/prototypes/archphene-terminal-app/out-linux/archphene-terminal.apk";archphene_require_file "$manager_apk";archphene_require_file "$terminal_apk";archphene_test_init "$serial";archphene_adb_run install -r "$manager_apk" >/dev/null;archphene_adb_run install -r "$terminal_apk" >/dev/null;packages="$(archphene_adb_run shell cmd package list packages -U)";manager_uid="$(sed -n 's/^package:org.archpheneos.manager uid:\([0-9]*\).*/\1/p'<<<"$packages")";terminal_uid="$(sed -n 's/^package:org.archpheneos.terminal uid:\([0-9]*\).*/\1/p'<<<"$packages")";[[ -n "$manager_uid" && -n "$terminal_uid" && "$manager_uid" != "$terminal_uid" ]] || archphene_die 'manager and Terminal UIDs are not isolated';archphene_adb_run shell am start -W -n org.archpheneos.terminal/.TerminalActivity >/dev/null;archphene_wait_log 'PTY|terminal' 20 'ArchpheneTerminal:I AndroidRuntime:E *:S' >/dev/null;archphene_note "Terminal companion isolation passed: manager UID $manager_uid, Terminal UID $terminal_uid."
